[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$RepairServices,[switch]$ResetUpdateCache,[switch]$ScanForUpdates,[switch]$InstallUpdates,[switch]$RepairComponentStore,[string]$OutputPath="$env:USERPROFILE\Desktop\UpdateComplianceRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($RepairServices-or$ResetUpdateCache-or$ScanForUpdates-or$InstallUpdates-or$RepairComponentStore)){throw'Choose at least one repair action.'}
Get-HotFix|Sort-Object InstalledOn -Descending|Export-Csv (Join-Path $OutputPath 'hotfixes-before.csv') -NoTypeInformation
if($RepairServices){foreach($s in'wuauserv','bits','cryptsvc','trustedinstaller'){if(Get-Service $s -ErrorAction SilentlyContinue){if($PSCmdlet.ShouldProcess($s,'Set startup and start')){Set-Service $s -StartupType Manual;Start-Service $s -ErrorAction SilentlyContinue;L"Prepared $s"}}}}
if($ResetUpdateCache-and$PSCmdlet.ShouldProcess('Windows Update cache','Reset SoftwareDistribution and catroot2')){Stop-Service wuauserv,bits,cryptsvc -Force -ErrorAction SilentlyContinue;$stamp=Get-Date -Format yyyyMMddHHmmss;Rename-Item "$env:WINDIR\SoftwareDistribution" "SoftwareDistribution.old.$stamp" -ErrorAction SilentlyContinue;Rename-Item "$env:WINDIR\System32\catroot2" "catroot2.old.$stamp" -ErrorAction SilentlyContinue;Start-Service cryptsvc,bits,wuauserv -ErrorAction SilentlyContinue;L'Windows Update cache reset.'}
if($RepairComponentStore-and$PSCmdlet.ShouldProcess('Windows image','Run DISM RestoreHealth')){dism /Online /Cleanup-Image /RestoreHealth|Tee-Object -FilePath $Log -Append;L'Component store repaired.'}
if($ScanForUpdates-and$PSCmdlet.ShouldProcess('Windows Update','Start scan')){UsoClient StartScan;L'Update scan requested.'}
if($InstallUpdates){if(Get-Command Install-WindowsUpdate -ErrorAction SilentlyContinue){if($PSCmdlet.ShouldProcess('Windows Update','Install available updates')){Install-WindowsUpdate -AcceptAll -IgnoreReboot|Tee-Object -FilePath $Log -Append}}else{UsoClient StartDownload;Start-Sleep 5;UsoClient StartInstall;L'Update download and install requested.'}}
L'Repair workflow finished.'